const Web3 = require('web3');
const HDWalletProvider = require('@truffle/hdwallet-provider');

// Configure wallet provider
const privateKeys = ['YOUR_PRIVATE_KEY_1', 'YOUR_PRIVATE_KEY_2'];
const rpcUrl = 'https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID';

const provider = new HDWalletProvider(privateKeys, rpcUrl);
const web3 = new Web3(provider);

// Function to send ETH
async function sendETH(toAddress, amountInEther) {
  const accounts = await web3.eth.getAccounts();
  const fromAccount = accounts[0];
  const amountInWei = web3.utils.toWei(amountInEther.toString(), 'ether');

  const transactionObject = {
    to: toAddress,
    from: fromAccount,
    value: amountInWei
  };

  try {
    const receipt = await web3.eth.sendTransaction(transactionObject);
    console.log('Transaction successful:', receipt.transactionHash);
  } catch (error) {
    console.error('Transaction failed:', error);
  }
}

// Function to interact with a smart contract
async function interactWithContract(contractAddress, ABI, method, args) {
  const accounts = await web3.eth.getAccounts();
  const fromAccount = accounts[0];
  const contract = new web3.eth.Contract(ABI, contractAddress);

  try {
    const result = await contract.methods[method](...args).send({ from: fromAccount });
    console.log('Contract method executed:', result);
  } catch (error) {
    console.error('Contract method failed:', error);
  }
}

